mapper.select:
SELECT g.date, g.hour, g.totalIn, g.totalOut, ( SELECT COUNT(*) FROM parking_log WHERE entry_type = 'IN' AND DATE(logged_at) = g.date AND HOUR(logged_at) <= g.hour ) - ( SELECT COUNT(*) FROM parking_log WHERE entry_type = 'OUT' AND DATE(logged_at) = g.date AND HOUR(logged_at) <= g.hour ) AS currentCount FROM ( SELECT DATE(logged_at) AS date, HOUR(logged_at) AS hour, SUM(CASE WHEN entry_type = 'IN' THEN 1 ELSE 0 END) AS totalIn, SUM(CASE WHEN entry_type = 'OUT' THEN 1 ELSE 0 END) AS totalOut FROM parking_log WHERE 1=1
AND DATE(logged_at) >= #{startDate}
AND DATE(logged_at) <= #{endDate}
GROUP BY DATE(logged_at), HOUR(logged_at) ) g ORDER BY g.date, g.hour

SELECT g.date, NULL AS hour, g.totalIn, g.totalOut, ( SELECT COUNT(*) FROM parking_log WHERE entry_type = 'IN' AND DATE(logged_at) <= g.date ) - ( SELECT COUNT(*) FROM parking_log WHERE entry_type = 'OUT' AND DATE(logged_at) <= g.date ) AS currentCount FROM ( SELECT DATE(logged_at) AS date, SUM(CASE WHEN entry_type = 'IN' THEN 1 ELSE 0 END) AS totalIn, SUM(CASE WHEN entry_type = 'OUT' THEN 1 ELSE 0 END) AS totalOut FROM parking_log WHERE 1=1
AND DATE(logged_at) >= #{startDate}
AND DATE(logged_at) <= #{endDate}
GROUP BY DATE(logged_at) ) g ORDER BY g.date
